20	export function validateFlags<TOptions extends FlagOptions = FlagOptions>(
21	  ctx: ParseFlagsContext<Record<string, unknown>>,
22	  opts: ParseFlagsOptions<TOptions>,
23	  options: Map<string, FlagOptions> = new Map(),
24	): void {
25	  if (!opts.flags) {
26	    return;
27	  }
28	  setDefaultValues(ctx, opts);
29	
30	  const optionNames = Object.keys(ctx.flags);
31	  if (!optionNames.length && opts.allowEmpty) {
32	    return;
33	  }
34	
35	  if (ctx.standalone) {
36	    validateStandaloneOption(
37	      ctx,
38	      options,
39	      optionNames,
40	    );
41	    return;
42	  }
43	
44	  for (const [name, option] of options) {
45	    validateUnknownOption(option, opts);
46	    validateConflictingOptions(ctx, option);
47	    validateDependingOptions(ctx, option, opts);
48	    validateRequiredValues(ctx, option, name);
49	  }
50	
51	  validateRequiredOptions(ctx, options, opts);
52	}
