54	function validateUnknownOption<TOptions extends FlagOptions = FlagOptions>(
55	  option: FlagOptions,
56	  opts: ParseFlagsOptions<TOptions>,
57	) {
58	  if (!getOption(opts.flags ?? [], option.name)) {
59	    throw new UnknownOptionError(option.name, opts.flags ?? []);
60	  }
61	}
