63	/**
64	 * Adds all default values to ctx.flags and returns a boolean object map with
65	 * only the default option names `{ [OptionName: string]: boolean }`.
66	 */
67	function setDefaultValues<TOptions extends FlagOptions = FlagOptions>(
68	  ctx: ParseFlagsContext<Record<string, unknown>>,
69	  opts: ParseFlagsOptions<TOptions>,
70	) {
71	  if (!opts.flags?.length) {
72	    return;
73	  }
74	
75	  // Set default values
76	  for (const option of opts.flags) {
77	    let name: string | undefined;
78	    let defaultValue: unknown = undefined;
79	
80	    // if --no-[flag] is present set --[flag] default value to true
81	    if (option.name.startsWith("no-")) {
82	      const propName = option.name.replace(/^no-/, "");
83	      if (typeof ctx.flags[propName] !== "undefined") {
84	        continue;
85	      }
86	      const positiveOption = getOption(opts.flags, propName);
87	      if (positiveOption) {
88	        continue;
89	      }
90	      name = paramCaseToCamelCase(propName);
91	      defaultValue = true;
92	    }
93	
94	    if (!name) {
95	      name = paramCaseToCamelCase(option.name);
96	    }
97	
98	    // TODO: remove ignoreDefaults if flags module has support for environment variables
99	    const hasDefaultValue: boolean = (!opts.ignoreDefaults ||
100	      typeof opts.ignoreDefaults[name] === "undefined") &&
101	      typeof ctx.flags[name] === "undefined" && (
102	        typeof option.default !== "undefined" ||
103	        typeof defaultValue !== "undefined"
104	      );
105	
106	    if (hasDefaultValue) {
107	      ctx.flags[name] = getDefaultValue(option) ?? defaultValue;
108	      ctx.defaults[option.name] = true;
109	      if (typeof option.value === "function") {
110	        ctx.flags[name] = option.value(ctx.flags[name]);
111	      }
112	    }
113	  }
114	}
