116	function validateStandaloneOption(
117	  ctx: ParseFlagsContext,
118	  options: Map<string, FlagOptions>,
119	  optionNames: Array<string>,
120	): void {
121	  if (!ctx.standalone || optionNames.length === 1) {
122	    return;
123	  }
124	
125	  // Don't throw an error if all values are coming from the default option.
126	  for (const [_, opt] of options) {
