52	/**
53	 * Split options and arguments.
54	 * @param args Arguments definition: `--color, -c <color1:string> <color2:string>`
55	 *
56	 * For example: `-c, --color <color1:string> <color2:string>`
57	 *
58	 * Will result in:
59	 * ```json
60	 * {
61	 *   flags: [ "-c", "--color" ],
62	 *   typeDefinition: "<color1:string> <color2:string>",
63	 * }
64	 * ```
65	 */
66	export function splitArguments(
67	  args: string,
68	): SplitArgumentsResult {
69	  const parts = args.trim().split(/[, =] */g);
70	  const typeParts = [];
71	
72	  while (
73	    parts[parts.length - 1] &&
74	    ARGUMENT_REGEX.test(parts[parts.length - 1])
75	  ) {
76	    typeParts.unshift(parts.pop());
77	  }
78	
79	  const typeDefinition: string = typeParts.join(" ");
80	
81	  return { flags: parts, typeDefinition, equalsSign: args.includes("=") };
82	}
