98	export function parseArgumentsDefinition<T extends boolean>(
99	  argsDefinition: string | Array<string | ArgDefinition>,
100	  validate = true,
101	  all?: T,
102	): T extends true ? Array<Argument | string> : Array<Argument> {
103	  const argumentDetails: Array<Argument | string> = [];
104	
105	  let hasOptional = false;
106	  let hasVariadic = false;
107	  const parts: Array<string | ArgDefinition> = Array.isArray(argsDefinition)
108	    ? argsDefinition
109	    : argsDefinition.split(/ +/);
110	
111	  for (let argDef of parts) {
112	    if (typeof argDef === "string") {
113	      argDef = { arg: argDef };
114	    }
115	    if (validate && hasVariadic) {
116	      throw new UnexpectedArgumentAfterVariadicArgumentError(argDef.arg);
117	    }
118	    const parts: string[] = argDef.arg.split(ARGUMENT_DETAILS_REGEX);
119	
120	    if (!parts[1]) {
121	      if (all) {
122	        argumentDetails.push(parts[0]);
123	      }
124	      continue;
125	    }
126	    const type: string | undefined = parts[2] || "string";
127	
128	    const details: Argument = {
129	      description: argDef.description,
130	      optional: argDef.arg[0] === "[",
131	      raw: argDef.arg,
132	      name: parts[1],
133	      action: parts[3] || type,
134	      variadic: false,
135	      list: type ? argDef.arg.indexOf(type + "[]") !== -1 : false,
136	      type,
137	    };
138	
139	    if (validate && !details.optional && hasOptional) {
140	      throw new UnexpectedRequiredArgumentError(details.name);
141	    }
142	
143	    if (argDef.arg[0] === "[") {
144	      hasOptional = true;
145	    }
146	
147	    if (details.name.length > 3) {
148	      const istVariadicLeft = details.name.slice(0, 3) === "...";
149	      const istVariadicRight = details.name.slice(-3) === "...";
150	
151	      hasVariadic = details.variadic = istVariadicLeft || istVariadicRight;
152	
153	      if (istVariadicLeft) {
154	        details.name = details.name.slice(3);
155	      } else if (istVariadicRight) {
156	        details.name = details.name.slice(0, -3);
157	      }
158	    }
159	
160	    argumentDetails.push(details);
161	  }
162	
163	  return argumentDetails as (
164	    T extends true ? Array<Argument | string> : Array<Argument>
165	  );
166	}
