168	export function dedent(str: string): string {
169	  const lines = str.split(/\r?\n|\r/g);
170	  let text = "";
171	  let indent = 0;
172	
173	  for (const line of lines) {
174	    if (text || line.trim()) {
175	      if (!text) {
176	        text = line.trimStart();
177	        indent = line.length - text.length;
178	      } else {
179	        text += line.slice(indent);
180	      }
181	      text += "\n";
182	    }
183	  }
184	
185	  return text.trimEnd();
186	}
