[metadata] {"type": "create", "filePath": "/app/command/config/_rc_parser.ts", "content": "/**
 * Parse the content of an `.rc` config file into a plain object.
 *
 * Format rules:
 * - One `key=value` pair per line.
 * - Lines starting with `#` are comments.
 * - Empty lines are ignored.
 * - Values wrapped in double quotes preserve leading/trailing spaces and are
 *   never coerced.
 * - Unquoted `true`/`false` are coerced to booleans and unquoted numeric
 *   values are coerced to numbers.
 */
export function parseRcConfig(content: string): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  const lines = content.split(/\r?\n/);

  for (const line of lines) {
    const trimmed = line.trim();

    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    const separatorIndex = trimmed.indexOf("=");

    if (separatorIndex === -1) {
      throw new Error(`Invalid line: "${trimmed}"`);
    }

    const key = trimmed.slice(0, separatorIndex).trim();
    const rawValue = trimmed.slice(separatorIndex + 1).trim();

    if (!key) {
      throw new Error(`Invalid line: "${trimmed}"`);
    }

    result[key] = parseValue(rawValue);
  }

  return result;
}

function parseValue(rawValue: string): unknown {
  const quoted = rawValue.match(/^"([\s\S]*)"$/);

  if (quoted) {
    return quoted[1];
  }

  if (rawValue === "true") {
    return true;
  }

  if (rawValue === "false") {
    return false;
  }

  if (rawValue !== "" && !isNaN(Number(rawValue))) {
    return Number(rawValue);
  }

  return rawValue;
}
