export function kebabToCamelCase(str: string): string {
  return str.replace(/-([a-zA-Z0-9])/g, (_match, char: string) => char.toUpperCase());
}

/** Convert a dotted, kebab-case config key to a dotted, camel-case key. */
export function toCamelCaseKey(key: string): string {
  return key.split(".").map(kebabToCamelCase).join(".");
}

/** Flatten a nested object into a dot-notation map. Arrays are kept as-is. */
export function flattenConfig(
  values: Record<string, unknown>,
  prefix = "",
): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(values)) {
    const path = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      Object.assign(
        result,
        flattenConfig(value as Record<string, unknown>, path),
      );
    } else {
      result[path] = value;
    }
  }

  return result;
}

/** Resolve the config file name for a given format. */
export function resolveConfigFileName(name: string, format: string): string {
  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
}
