import { exists } from "@cliffy/internal/runtime/exists";
import { readTextFile } from "@cliffy/internal/runtime/read-text-file";
import { ConfigParseError } from "./_errors.ts";
import { resolveConfigFileName } from "./_utils.ts";
import { parseRcConfig } from "./_rc_parser.ts";
import type { ConfigOptions, ResolvedConfigFile } from "./types.ts";

const DEFAULT_SEARCH_PATHS = ["."];
const DEFAULT_FORMATS = [".json", ".rc"];

function parseContent(
  path: string,
  format: string,
  content: string,
  parser?: ConfigOptions["parser"],
): Record<string, unknown> {
  try {
    if (parser) {
      return parser(content);
    }
    if (format === ".json") {
      return JSON.parse(content);
    }
    if (format === ".rc") {
      return parseRcConfig(content);
    }
    throw new Error(`Unsupported config format "${format}".`);
  } catch (error) {
    throw new ConfigParseError(
      path,
      error instanceof Error ? error.message : String(error),
    );
  }
}

async function findConfigFile(
  searchPath: string,
  name: string,
  formats: Array<string>,
  parser?: ConfigOptions["parser"],
): Promise<ResolvedConfigFile | undefined> {
  for (const format of formats) {
    const path = join(searchPath, resolveConfigFileName(name, format));

    if (await exists(path)) {
      const content = await readTextFile(path);
      return { path, values: parseContent(path, format, content, parser) };
    }
  }

  return undefined;
}

/** Search for and parse a config file according to the given config options. */
export async function resolveConfig(
  options: ConfigOptions,
): Promise<ResolvedConfigFile | undefined> {
  const searchPaths = options.searchPaths?.length
    ? options.searchPaths
    : DEFAULT_SEARCH_PATHS;
  const formats = options.formats?.length ? options.formats : DEFAULT_FORMATS;

  if (!options.mergeConfigs) {
    for (const searchPath of searchPaths) {
      const result = await findConfigFile(
        searchPath,
        options.name,
        formats,
        options.parser,
      );
      if (result) {
        return result;
      }
    }
    return undefined;
  }

  const results: Array<ResolvedConfigFile> = [];

  for (const searchPath of searchPaths) {
    const result = await findConfigFile(
      searchPath,
      options.name,
      formats,
      options.parser,
    );
    if (result) {
      results.push(result);
    }
  }

  if (!results.length) {
    return undefined;
  }

  const values: Record<string, unknown> = {};
  for (const result of results.slice().reverse()) {
    Object.assign(values, result.values);
  }

  return { path: results[0].path, values };
}
